import React, { useMemo, useState } from "react";
import { Container, Form, Modal, Row, Col } from "react-bootstrap";
import ProjectCard from "./ProjectCards";
import Particle from "../Particle";
import { projects } from "../../data/projects";
import { useInViewOnce } from "../../hooks/useInViewOnce";
import { Trans, useTranslation } from "react-i18next";

function Projects() {
  const header = useInViewOnce();
  const { t, i18n } = useTranslation();
  const [query, setQuery] = useState("");
  const [theme, setTheme] = useState("All");
  const [activeId, setActiveId] = useState(null);

  const themes = useMemo(
    () => [
      { id: "All", label: t("projects.theme_all") },
      { id: "Security", label: t("projects.theme_security") },
      { id: "Cloud", label: t("projects.theme_cloud") },
      { id: "DevOps", label: t("projects.theme_devops") },
      { id: "Infrastructure", label: t("projects.theme_infra") },
      { id: "Development", label: t("projects.theme_dev") },
      { id: "Data/ML", label: t("projects.theme_data") },
      { id: "Other", label: t("projects.theme_other") },
    ],
    [t]
  );

  const getTheme = (p) => {
    const tags = Array.isArray(p.tags) ? p.tags : [];
    const lang = String(p.language ?? "");
    const hay = `${tags.join(" ")} ${lang}`.toLowerCase();

    const has = (needle) => hay.includes(needle);

    if (has("soc") || has("siem") || has("malware") || has("c2") || has("cyber") || has("security") || has("wazuh")) {
      return "Security";
    }
    if (has("aws") || has("azure") || has("cloud") || has("localstack") || has("lambda") || has("api gateway")) {
      return "Cloud";
    }
    if (has("devops") || has("ci/cd") || has("jenkins") || has("argocd") || has("helm") || has("docker") || has("kubernetes") || has("k3s") || has("k3d") || has("ansible") || has("packer") || has("sonarqube")) {
      return "DevOps";
    }
    if (has("infrastructure") || has("iac") || has("backup") || has("pra") || has("pca")) {
      return "Infrastructure";
    }
    if (has("react") || has("typescript") || has("python") || has("c#") || has("csharp") || has("c") || has("tkinter") || has("unity") || has("automation")) {
      return "Development";
    }
    if (has("neuralnetwork") || has("neural network") || has("ocr") || has("ml")) {
      return "Data/ML";
    }
    return "Other";
  };

  const ordered = useMemo(() => {
    return [...projects].sort((a, b) => {
      const ra = typeof a.rank === "number" ? a.rank : 0;
      const rb = typeof b.rank === "number" ? b.rank : 0;
      if (rb !== ra) return rb - ra;
      return (a.title ?? "").localeCompare(b.title ?? "");
    });
  }, []);

  const isFr = i18n.language?.toLowerCase().startsWith("fr");
  const projectDesc = useMemo(
    () => (p) => {
      if (!p) return "";
      return isFr ? (p.description_fr ?? p.description) : p.description;
    },
    [isFr]
  );
  const projectDetails = useMemo(
    () => (p) => {
      if (!p) return [];
      return isFr ? (p.details_fr ?? p.details) : p.details;
    },
    [isFr]
  );

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return ordered.filter((p) => {
      const matchesTheme = theme === "All" || getTheme(p) === theme;
      const hay = `${p.title} ${projectDesc(p)} ${p.language} ${(p.tags ?? []).join(" ")}`.toLowerCase();
      const matchesQuery = q.length === 0 || hay.includes(q);
      return matchesTheme && matchesQuery;
    });
  }, [ordered, query, theme, projectDesc]);

  const active = useMemo(() => projects.find((p) => p.id === activeId) ?? null, [activeId]);

  return (
    <Container fluid className="project-section">
      <Particle />
      <Container>
        <div
          ref={header.ref}
          className={`projects-header section-card reveal ${header.isInView ? "is-visible" : ""}`}
        >
          <div className="section-header">
            <h1 className="section-title">
              {t("projects.title_prefix")} <span className="purple">{t("projects.title_highlight")}</span>
            </h1>
            <p className="section-subtitle">
              {t("projects.subtitle")}
            </p>
          </div>

          <div className="projects-controls">
            <Form.Control
              className="projects-search"
              placeholder={t("projects.search_placeholder")}
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />

            <div className="projects-themes">
              {themes.map((t) => (
                <button
                  key={t.id}
                  type="button"
                  className={`theme-chip ${t.id === theme ? "is-active" : ""}`}
                  onClick={() => setTheme(t.id)}
                >
                  {t.label}
                </button>
              ))}
            </div>
          </div>

          <div className="projects-meta">
            <Trans
              i18nKey="projects.showing"
              values={{ shown: filtered.length, total: projects.length }}
              components={{
                1: <span className="purple" />,
                3: <span className="purple" />,
              }}
            />
          </div>
        </div>

        <Row style={{ justifyContent: "center", paddingBottom: "10px" }}>
          {filtered.map((project) => (
            <Col key={project.id} md={6} lg={4} className="project-card">
              <div className="reveal is-visible">
                <ProjectCard
                  imgPath={project.image}
                  title={project.title}
                  description={projectDesc(project)}
                  tags={project.tags}
                  ghLink={project.links?.github}
                  demoLink={project.links?.demo}
                  onOpen={() => setActiveId(project.id)}
                />
              </div>
            </Col>
          ))}
        </Row>

        {active && (
          <Modal show onHide={() => setActiveId(null)} centered contentClassName="skill-modal">
          <Modal.Header closeButton>
            <Modal.Title>{active?.title}</Modal.Title>
          </Modal.Header>
          <Modal.Body>
            <div className="project-modal-tags">
              {(active?.tags ?? []).map((t) => (
                <span key={`modal-${active?.id}-${t}`} className="project-tag">
                  {t}
                </span>
              ))}
            </div>
            <div className="project-modal-stack">{active?.language}</div>
            <div className="project-modal-desc">
              {projectDetails(active)?.length
                ? projectDetails(active).map((para, i) => <p key={i}>{para}</p>)
                : <p>{projectDesc(active)}</p>
              }
            </div>

            {(active?.links?.github || active?.links?.demo) && (
              <div className="project-card-actions">
                {active?.links?.github && (
                  <a className="btn btn-primary project-card-btn" href={active.links.github} target="_blank" rel="noreferrer">
                    {t("projects.modal_github")}
                  </a>
                )}
                {active?.links?.demo && (
                  <a className="btn btn-outline-primary project-card-btn" href={active.links.demo} target="_blank" rel="noreferrer">
                    {t("projects.modal_demo")}
                  </a>
                )}
              </div>
            )}
          </Modal.Body>
          </Modal>
        )}
      </Container>
    </Container>
  );
}

export default Projects;
