import React from "react";
import Card from "react-bootstrap/Card";
import Button from "react-bootstrap/Button";
import { BsFillFileEarmarkCodeFill } from "react-icons/bs";
import { useTranslation } from "react-i18next";

function ProjectCards(props) {
  const { t } = useTranslation();
  const hasGithub = typeof props.ghLink === "string" && props.ghLink.trim().length > 0;
  const hasDemo = typeof props.demoLink === "string" && props.demoLink.trim().length > 0;
  const tags = Array.isArray(props.tags) ? props.tags : [];

  return (
    <Card className="project-card-view" role="button" onClick={props.onOpen}>
      <Card.Img
        variant="top"
        className="project-card-img"
        src={props.imgPath}
        alt={`${props.title} screenshot`}
        loading="lazy"
        decoding="async"
      />
      <Card.Body>
        <Card.Title>{props.title}</Card.Title>
        <div className="project-card-tags">
          {tags.slice(0, 4).map((t) => (
            <span key={`${props.title}-${t}`} className="project-tag">
              {t}
            </span>
          ))}
        </div>
        <Card.Text className="project-card-desc">
          {props.description}
        </Card.Text>
        {hasDemo && (
          <div className="project-card-actions" onClick={(e) => e.stopPropagation()}>
            <Button
              variant="outline-primary"
              href={props.demoLink}
              target="_blank"
              rel="noreferrer"
              className="project-card-btn"
            >
              {t("projects.live_demo")}
            </Button>
          </div>
        )}

        <div className="project-card-meta" onClick={(e) => e.stopPropagation()}>
          {hasGithub ? (
            <a className="project-card-repo" href={props.ghLink} target="_blank" rel="noreferrer">
              <BsFillFileEarmarkCodeFill /> &nbsp; {t("projects.repo")}
            </a>
          ) : (
            <span className="project-card-repo-missing">{t("projects.repo_missing")}</span>
          )}
        </div>
      </Card.Body>
    </Card>
  );
}
export default ProjectCards;
